var ccd = Oculars.getCCD(0);
if(ccd.hasOAG()) {
    core.debug("CCD has Off-Axis Guider");
}

var telescope = Oculars.getTelescope(0);
var ccd = Oculars.getCCD(0);
var fovX = ccd.getActualFOVx(telescope, null);
core.debug("CCD FOV: " + fovX.toFixed(2) + "°");

var ocular = Oculars.getOcular(0);
if(ocular.isBinoculars()) {
    core.debug("This is a binocular");
}

var ocular = Oculars.getOcular(0);
if(ocular.hasPermanentCrosshair()) {
    core.debug("Eyepiece has reticle");
}

var telescope = Oculars.getTelescope(0);
var ocular = Oculars.getOcular(0);
var fov = ocular.actualFOV(telescope, null);
core.debug("Eyepiece FOV: " + fov.toFixed(2) + "°");

var telescope = Oculars.getTelescope(0);
var ocular = Oculars.getOcular(0);
var mag = ocular.magnification(telescope, null);
core.debug("Magnification: " + mag.toFixed(1) + "x");

var scope = Oculars.getTelescope(0);
if(scope.isHFlipped()) {
    core.debug("Image is horizontally flipped");
}

var scope = Oculars.getTelescope(0);
if(scope.isVFlipped()) {
    core.debug("Image is vertically flipped");
}

var scope = Oculars.getTelescope(0);
if(scope.isEquatorial()) {
    core.debug("Equatorial mount");
} else {
    core.debug("Alt-Azimuth mount");
}

if(Oculars.getEnableOcular()) {
    core.debug("Ocular view is active");
} else {
    Oculars.enableOcular(true);
}

// Enable eyepiece simulation
Oculars.enableOcular(true);

// Disable and return to normal view
Oculars.enableOcular(false);

if(Oculars.getEnableCrosshairs()) {
    core.debug("Crosshairs are visible");
}

// Show crosshairs in ocular view
Oculars.toggleCrosshairs(true);

// Hide crosshairs
Oculars.toggleCrosshairs(false);

if(Oculars.getEnableCCD()) {
    core.debug("CCD sensor frame is visible");
}

// Show camera sensor frame
Oculars.toggleCCD(true);

// Hide sensor frame
Oculars.toggleCCD(false);

if(Oculars.getEnableTelrad()) {
    core.debug("Telrad circles are visible");
}

// Show Telrad finder
Oculars.toggleTelrad(true);

// Hide Telrad
Oculars.toggleTelrad(false);

var lensIndex = Oculars.getSelectedLensIndex();
if(lensIndex >= 0) {
    core.debug("Active lens index: " + lensIndex);
}

// Select the first Barlow lens
Oculars.selectLensAtIndex(0);

// Disable auxiliary lens
Oculars.selectLensAtIndex(-1);

if(Oculars.getFlagGuiPanelEnabled()) {
    core.debug("Oculars control panel is visible");
}

// Show the control panel
Oculars.enableGuiPanel(true);

// Hide the control panel
Oculars.enableGuiPanel(false);

if(Oculars.getFlagInitFovUsage()) {
    core.debug("Initial FOV will be restored");
}

if(Oculars.getFlagInitDirectionUsage()) {
    core.debug("Initial direction will be restored");
}

if(Oculars.getFlagShowResolutionCriteria()) {
    core.debug("Resolution criteria displayed");
}

if(Oculars.getFlagRequireSelection()) {
    core.debug("Select an object first");
}

if(Oculars.getFlagAutoLimitMagnitude()) {
    core.debug("Auto magnitude limiting is active");
}

// Enable automatic magnitude limiting
Oculars.setFlagAutoLimitMagnitude(true);

// Use manual magnitude limit
Oculars.setFlagAutoLimitMagnitude(false);

if(Oculars.getFlagHideGridsLines()) {
    core.debug("Constellation lines are hidden in ocular view");
}

if(Oculars.getFlagScaleImageCircle()) {
    core.debug("Ocular circle scales with aFOV");
}

if(Oculars.getFlagUseSemiTransparency()) {
    core.debug("Semi-transparent mask enabled");
}

// Enable semi-transparent mask
Oculars.setFlagUseSemiTransparency(true);

// Use fully opaque mask
Oculars.setFlagUseSemiTransparency(false);

// 50% transparent mask
Oculars.setTransparencyMask(50);

// Fully opaque mask
Oculars.setTransparencyMask(0);

if(Oculars.getFlagDMSDegrees()) {
    core.debug("Coordinates in DMS format");
} else {
    core.debug("Coordinates in decimal degrees");
}

// Use DMS format
Oculars.setFlagDMSDegrees(true);

// Use decimal degrees
Oculars.setFlagDMSDegrees(false);

if(Oculars.getFlagHorizontalCoordinates()) {
    core.debug("Using Alt/Az coordinates");
} else {
    core.debug("Using RA/Dec coordinates");
}

// Use Alt/Az for CCD cross
Oculars.setFlagHorizontalCoordinates(true);

// Use RA/Dec
Oculars.setFlagHorizontalCoordinates(false);

if(Oculars.getFlagAutosetMountForCCD()) {
    core.debug("Mount auto-set enabled");
}

if(Oculars.getFlagScalingFOVForTelrad()) {
    core.debug("Telrad auto-zoom enabled");
}

// Set standard Telrad circles
var circles = core.vec4f(0.5, 2.0, 4.0, 0.0);
Oculars.setTelradFOV(circles);

if(Oculars.getFlagScalingFOVForCCD()) {
    core.debug("CCD auto-zoom enabled");
}

if(Oculars.getFlagMaxExposureTimeForCCD()) {
    core.debug("Max exposure time displayed");
}

if(Oculars.getFlagShowOcularsButton()) {
    core.debug("Oculars button is visible");
}

// Show Oculars button in toolbar
Oculars.setFlagShowOcularsButton(true);

// Hide Oculars button
Oculars.setFlagShowOcularsButton(false);

if(Oculars.getFlagShowContour()) {
    core.debug("Ocular contour is visible");
}

if(Oculars.getFlagShowCardinals()) {
    core.debug("Cardinal markers displayed in ocular");
}

if(Oculars.getFlagAlignCrosshair()) {
    core.debug("Crosshair aligned with celestial pole");
}

// Make arrow buttons larger
Oculars.setArrowButtonScale(200);

// Default size
Oculars.setArrowButtonScale(150);

// Set text to bright yellow
var yellow = core.vec3f(1.0, 0.9, 0.2);
Oculars.setTextColor(yellow);

// Set text to white
var white = core.vec3f(1.0, 1.0, 1.0);
Oculars.setTextColor(white);

// Set lines to bright red
var red = core.vec3f(1.0, 0.2, 0.2);
Oculars.setLineColor(red);

// Set lines to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
Oculars.setLineColor(cyan);

// Set focuser overlay to bright blue
var blue = core.vec3f(0.2, 0.5, 1.0);
Oculars.setFocuserColor(blue);

if(Oculars.getFlagShowCcdCropOverlay()) {
    core.debug("CCD crop overlay visible");
}

if(Oculars.getFlagShowCcdCropOverlayPixelGrid()) {
    core.debug("Pixel grid visible in crop overlay");
}

// Set crop to 500x500 pixels
Oculars.setCcdCropOverlayHSize(500);
Oculars.setCcdCropOverlayVSize(500);

if(Oculars.getFlagShowFocuserOverlay()) {
    core.debug("Focuser overlay visible");
}

if(Oculars.getFlagUseSmallFocuserOverlay()) {
    core.debug("Small focuser (1.25\") overlay visible");
}

if(Oculars.getFlagUseMediumFocuserOverlay()) {
    core.debug("Medium focuser (2.0\") overlay visible");
}

if(Oculars.getFlagUseLargeFocuserOverlay()) {
    core.debug("Large focuser (3.3\") overlay visible");
}

if(Oculars.getFlagShowOAGLimits()) {
    core.debug("OAG guider limits visible");
}

var settings = Oculars.getSettings();
// Access settings values
var ocularCount = settings.value("ocular_count", 0).toInt();

// Rotate CCD frame 90 degrees
Oculars.rotateCCD(90);

// Rotate back 45 degrees
Oculars.rotateCCD(-45);
